func TestNew(t *testing.T) {
	tr := New("script_")
	if tr.prefix != "script_" {
		t.Errorf("prefix = %q", tr.prefix)
	}
	if tr.scripts == nil {
		t.Error("scripts map not initialized")
	}
}

func TestIsExist(t *testing.T) {
	tr := New("script_")
	tr.scripts["weather"] = &Script{Doc: ScriptDoc{Name: "weather"}}

	if !tr.IsExist("script_weather") {
		t.Error("expected weather to exist with prefix")
	}
	if !tr.IsExist("weather") {
		t.Error("expected weather to exist without prefix")
	}
	if tr.IsExist("script_nonexistent") {
		t.Error("expected nonexistent to not exist")
	}
}

func TestGetTools(t *testing.T) {
	tr := New("script_")
	tr.scripts["test"] = &Script{
		Doc: ScriptDoc{
			Name:        "test",
			Description: "A test tool",
			Parameters:  json.RawMessage(`{"type":"object","properties":{"q":{"type":"string"}}}`),
		},
	}

	tools := tr.GetTools()
	if len(tools) != 1 {
		t.Fatalf("len = %d, want 1", len(tools))
	}

	fn := tools[0]["function"].(map[string]any)
	if fn["name"] != "script_test" {
		t.Errorf("name = %v", fn["name"])
	}
	if fn["description"] != "A test tool" {
		t.Errorf("description = %v", fn["description"])
	}

	params := fn["parameters"].(json.RawMessage)
	var p map[string]any
	json.Unmarshal(params, &p)
	if p["type"] != "object" {
		t.Errorf("params type = %v", p["type"])
	}
}

