func TestAlwaysAllowNames(t *testing.T) {
	tr := New("script_")
	tr.scripts["a"] = &Script{Doc: ScriptDoc{Name: "a", AlwaysAllow: true}}
	tr.scripts["b"] = &Script{Doc: ScriptDoc{Name: "b", AlwaysAllow: false}}
	tr.scripts["c"] = &Script{Doc: ScriptDoc{Name: "c", AlwaysAllow: true}}

	names := tr.AlwaysAllowNames()
	if len(names) != 2 {
		t.Fatalf("len = %d, want 2", len(names))
	}
	if !slices.Contains(names, "script_a") || !slices.Contains(names, "script_c") {
		t.Errorf("names = %v", names)
	}
}

