func TestTimeouts(t *testing.T) {
	tr := New("script_")
	tr.scripts["fast"] = &Script{Doc: ScriptDoc{Name: "fast", Timeout: 10}}
	tr.scripts["slow"] = &Script{Doc: ScriptDoc{Name: "slow", Timeout: 600}}
	tr.scripts["default"] = &Script{Doc: ScriptDoc{Name: "default"}}

	timeouts := tr.Timeouts()
	if timeouts["script_fast"] != 10 {
		t.Errorf("fast timeout = %d", timeouts["script_fast"])
	}
	if timeouts["script_slow"] != 600 {
		t.Errorf("slow timeout = %d", timeouts["script_slow"])
	}
	if _, ok := timeouts["script_default"]; ok {
		t.Error("default (0) timeout should not be in map")
	}
}

func TestScan(t *testing.T) {
	root := t.TempDir()

	toolDir := filepath.Join(root, "my_script")
	os.MkdirAll(toolDir, 0755)

	doc := ScriptDoc{Name: "my_script", Description: "Test script"}
	raw, _ := json.Marshal(doc)
	os.WriteFile(filepath.Join(toolDir, "tool.json"), raw, 0644)
	os.WriteFile(filepath.Join(toolDir, "script.js"), []byte("console.log('hello')"), 0644)

	hidden := filepath.Join(root, "_skip")
	os.MkdirAll(hidden, 0755)

	dotHidden := filepath.Join(root, ".hidden")
	os.MkdirAll(dotHidden, 0755)

	tr := New("script_")
	if err := tr.Scan(root); err != nil {
		t.Fatalf("Scan: %v", err)
	}

	if !tr.IsExist("script_my_script") {
		t.Error("expected my_script to exist")
	}
	if len(tr.scripts) != 1 {
		t.Errorf("scripts count = %d, want 1", len(tr.scripts))
	}
}

